    if (!page) return false;
    const container = page.querySelector('.text-container');
    const containerRect = container.getBoundingClientRect();

    // Calculate split point relative to container's bottom edge
    // Because the HTML uses 'bottom: ...px' as its primary coordinate
    const splitY_fromBottom = containerRect.bottom - rect.bottom;

    if (doc.querySelector('.in-book-widget')) win.closeMironWidget();

